import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.5wcOFaQl.js";const c=JSON.parse('{"title":"Data Science, DevOps & mehr 📊⚙️","description":"","frontmatter":{},"headers":[],"relativePath":"skills/data-devops-email.md","filePath":"skills/data-devops-email.md"}'),n={name:"skills/data-devops-email.md"};function r(l,e,h,o,d,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="data-science-devops-mehr-📊⚙️" tabindex="-1">Data Science, DevOps &amp; mehr 📊⚙️ <a class="header-anchor" href="#data-science-devops-mehr-📊⚙️" aria-label="Permalink to &quot;Data Science, DevOps &amp; mehr 📊⚙️&quot;">​</a></h1><p>Kleinere Kategorien zusammengefasst: Data Science, DevOps, Dogfood und Email.</p><hr><h2 id="📊-data-science" tabindex="-1">📊 Data Science <a class="header-anchor" href="#📊-data-science" aria-label="Permalink to &quot;📊 Data Science&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>jupyter-live-kernel</strong></td><td>Iteratives Python via live Jupyter-Kernel</td></tr></tbody></table><h3 id="jupyter-live-kernel" tabindex="-1">jupyter-live-kernel <a class="header-anchor" href="#jupyter-live-kernel" aria-label="Permalink to &quot;jupyter-live-kernel&quot;">​</a></h3><p><strong>Auslöser:</strong> „Analysier die Daten&quot;, „Mach ne Visualisierung&quot;, „Jupyter&quot;</p><p>Startet einen live Jupyter-Kernel (hamelnb), in dem Hermes interaktive Python-Analysen ausführen kann. Besonders nützlich für: Datenexploration, statistische Auswertungen, Plotting.</p><p><strong>Vorteile gegenüber terminal():</strong></p><ul><li>Zwischenergebnisse bleiben im Kernel erhalten</li><li>Variablen können in späteren Schritten weiterverwendet werden</li><li>Kein wiederholtes Laden großer Datensätze</li></ul><hr><h2 id="⚙️-devops" tabindex="-1">⚙️ DevOps <a class="header-anchor" href="#⚙️-devops" aria-label="Permalink to &quot;⚙️ DevOps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>webhook-subscriptions</strong></td><td>Webhook-Abos: ereignisgesteuerte Agenten-Ausführungen</td></tr></tbody></table><h3 id="webhook-subscriptions" tabindex="-1">webhook-subscriptions <a class="header-anchor" href="#webhook-subscriptions" aria-label="Permalink to &quot;webhook-subscriptions&quot;">​</a></h3><p><strong>Auslöser:</strong> „Trigger bei Webhook&quot;, „Event-basierte Tasks&quot;</p><p>Richtet Webhook-Endpoints ein, die bei bestimmten Ereignissen (Git-Push, CI-Fail, etc.) automatisch eine Hermes-Session starten. Der Agent führt dann eine vordefinierte Aufgabe aus.</p><p><strong>Anwendungen:</strong></p><ul><li>Automatischer Deployment-Check bei Git-Push</li><li>Fehleranalyse bei CI-Fail</li><li>Tägliche Zusammenfassungen via Webhook-Trigger</li></ul><hr><h2 id="🐶-dogfood" tabindex="-1">🐶 Dogfood <a class="header-anchor" href="#🐶-dogfood" aria-label="Permalink to &quot;🐶 Dogfood&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>dogfood</strong></td><td>Explorative QA von Web-Apps: Bugs finden, Belege sammeln, Reports</td></tr></tbody></table><p><strong>Auslöser:</strong> „Teste die Web-App&quot;, „Finde Bugs&quot;, „QA-Check&quot;</p><p>Der Dogfood-Skill navigiert systematisch durch Web-Apps, sucht nach Bugs, macht Screenshots und erstellt einen QA-Report. Nützt den Browser, um die App wie ein echter User zu erkunden.</p><hr><h2 id="📧-email" tabindex="-1">📧 Email <a class="header-anchor" href="#📧-email" aria-label="Permalink to &quot;📧 Email&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>himalaya</strong></td><td>Himalaya CLI: IMAP/SMTP-Email aus dem Terminal</td></tr></tbody></table><p><strong>Auslöser:</strong> „Lies meine Mails&quot;, „Schick ne Email&quot;, „Such in Mails&quot;</p><p>Himalaya ist ein CLI-Email-Client, den Hermes direkt ansteuern kann: Mails lesen, durchsuchen, senden, Anhänge verwalten – alles aus dem Terminal.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mails lesen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">himalaya</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INBOX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mail senden</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">himalaya</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --subject</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Hallo&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --body</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Text&quot;</span></span></code></pre></div>`,29)])])}const k=t(n,[["render",r]]);export{c as __pageData,k as default};
